import React, { useEffect, useMemo, useState } from "react";
import WeatherOverlay from "./WeatherOverlay";
import Radar from "./Radar";
import Forecast from "./Forecast";
import BottomBar from "./BottomBar";
import SearchSection from "./SearchSection";
import Community from "./Community";
import Hourly from "./Hourly"; // <-- NEW: render hourly list

const API_BASE = process.env.REACT_APP_API_BASE || "http://127.0.0.1:8000";

const ATL = { name: "Atlanta,US", lat: 33.749, lon: -84.388 };
const isFiniteNum = (n) => typeof n === "number" && isFinite(n);
const toF = (c) => (c == null ? null : (c * 9) / 5 + 32);

// ---------- POP & precip helpers ----------
function normPop(p) {
  if (p == null || Number.isNaN(Number(p))) return 0;
  let x = Number(p);
  if (x > 1) x = x / 100; // 42 -> 0.42
  return Math.max(0, Math.min(1, x));
}
function getPrecipAmount(src) {
  // number (mm) or object with 1h/3h
  if (src == null) return 0;
  if (typeof src === "number") return src;
  if (typeof src === "object") {
    if (typeof src["1h"] === "number") return src["1h"];
    if (typeof src["3h"] === "number") return src["3h"];
  }
  return 0;
}

// ---------- condition normalizer ----------
function normalizeCondition(input) {
  if (typeof input === "string") return input.toLowerCase().trim();

  if (Array.isArray(input) && input.length) {
    const first = input[0];
    if (typeof first === "string") return first.toLowerCase().trim();
    if (first && typeof first === "object") {
      if (typeof first.description === "string") return first.description.toLowerCase().trim();
      if (typeof first.main === "string") return first.main.toLowerCase().trim();
    }
  }

  if (input && typeof input === "object") {
    if (typeof input.description === "string") return input.description.toLowerCase().trim();
    if (typeof input.main === "string") return input.main.toLowerCase().trim();
  }

  if (typeof input === "number") {
    const code = input;
    if ([95, 96, 99].includes(code)) return "thunderstorm";
    if ([71, 73, 75, 77, 85, 86].includes(code)) return "snow";
    if ([51, 53, 55, 56, 57, 61, 63, 65, 66, 67, 80, 81, 82].includes(code)) return "rain";
    if ([45, 48].includes(code)) return "fog";
    if ([0, 1].includes(code)) return "clear";
    return "clouds";
  }

  return "clear";
}

function fallbackIsDay() {
  const h = new Date().getHours();
  return h >= 6 && h < 18;
}

// ---------- HOURLY extractors for common providers ----------
function extractHourly(root) {
  // 1) OpenWeather / similar: array already at root.hourly
  if (Array.isArray(root?.hourly)) {
    return root.hourly.map((h, i) => ({
      dt: h.dt ?? h.date ?? Math.floor(Date.now() / 1000) + (i + 1) * 3600,
      temp: h.temp ?? h.temperature ?? null,
      pop: normPop(h.pop),
      precipitation:
        h.precipitation ??
        getPrecipAmount(h.rain) ??
        getPrecipAmount(h.snow) ??
        0,
      weather: h.weather ?? h.description ?? "",
    }));
  }

  // 2) Common nests
  const nested =
    root?.forecast?.hourly ||
    root?.timeline?.hourly ||
    root?.hours ||
    root?.hour;
  if (Array.isArray(nested)) {
    return nested.map((h, i) => ({
      dt: h.dt ?? h.date ?? h.time ?? Math.floor(Date.now() / 1000) + (i + 1) * 3600,
      temp: h.temp ?? h.temperature ?? h.temp_c ?? h.temp_f ?? null,
      pop: normPop(h.pop ?? h.probability ?? h.precipitation_probability),
      precipitation:
        h.precipitation ??
        getPrecipAmount(h.rain) ??
        getPrecipAmount(h.snow) ??
        h.precip ??
        0,
      weather: h.weather ?? h.description ?? h.condition ?? "",
    }));
  }

  // 3) Tomorrow.io v4 style: timelines.hourly[].values
  const tl = root?.timelines?.hourly;
  if (Array.isArray(tl)) {
    return tl.map((row, i) => {
      const v = row?.values || {};
      return {
        dt: row?.time ? Math.floor(new Date(row.time).getTime() / 1000) : Math.floor(Date.now() / 1000) + (i + 1) * 3600,
        temp: v.temperature ?? v.temperatureApparent ?? null,
        pop: normPop(v.precipitationProbability),
        precipitation: v.precipitationIntensity ?? v.rainIntensity ?? 0, // mm/hr typically
        weather: v.weatherCode ?? "",
      };
    });
  }

  // 4) Open‑Meteo style: column arrays under root.hourly
  if (root?.hourly && typeof root.hourly === "object") {
    const col = root.hourly;
    const times = Array.isArray(col.time) ? col.time : [];
    const temps = Array.isArray(col.temperature_2m) ? col.temperature_2m : [];
    const precips = Array.isArray(col.precipitation) ? col.precipitation : [];
    const pops = Array.isArray(col.precipitation_probability) ? col.precipitation_probability : [];
    const res = [];
    const n = Math.max(times.length, temps.length, precips.length, pops.length);
    for (let i = 0; i < n; i++) {
      const ts = times[i] ? Math.floor(new Date(times[i]).getTime() / 1000) : Math.floor(Date.now() / 1000) + (i + 1) * 3600;
      res.push({
        dt: ts,
        temp: temps[i] ?? null,
        pop: normPop(pops[i]),
        precipitation: typeof precips[i] === "number" ? precips[i] : 0,
        weather: "",
      });
    }
    if (res.length) return res;
  }

  // 5) Some APIs return 3‑hourly at root.list (OpenWeather /forecast)
  if (Array.isArray(root?.list)) {
    const out = [];
    for (let i = 0; i < root.list.length && out.length < 24; i++) {
      const h = root.list[i];
      out.push({
        dt: h.dt ?? Math.floor(Date.now() / 1000) + (out.length + 1) * 10800,
        temp: h.main?.temp ?? null,
        pop: normPop(h.pop),
        precipitation:
          getPrecipAmount(h.rain) ?? getPrecipAmount(h.snow) ?? 0,
        weather: h.weather ?? h.description ?? "",
      });
    }
    if (out.length) return out;
  }

  // 6) Hourly under different wrappers
  if (Array.isArray(root?.hourly?.data)) {
    return root.hourly.data.map((h, i) => ({
      dt: h.time ?? h.dt ?? Math.floor(Date.now() / 1000) + (i + 1) * 3600,
      temp: h.temp ?? h.temperature ?? null,
      pop: normPop(h.pop ?? h.probability),
      precipitation: h.precipitation ?? getPrecipAmount(h.rain) ?? getPrecipAmount(h.snow) ?? 0,
      weather: h.weather ?? h.description ?? "",
    }));
  }

  return [];
}

// ---------- normalize backend payload into a stable shape ----------
function normalizePayload(p) {
  if (!p || typeof p !== "object") {
    return { current: null, hourly: [], daily: [], summary: "", timezone: null, _raw: p };
  }
  const root = p.weather && typeof p.weather === "object" ? p.weather : p;

  // current
  const cur = root.current || {};
  const current = {
    temp: cur.temp ?? cur.temperature ?? null,
    weather: cur.weather ?? cur.description ?? "",
    precipitation:
      cur.precipitation ??
      getPrecipAmount(cur.rain) ??
      getPrecipAmount(cur.snow) ??
      0,
    dt: cur.dt ?? Math.floor(Date.now() / 1000),
    sunrise: cur.sunrise ?? null,
    sunset: cur.sunset ?? null,
    is_day: typeof cur.is_day === "number" ? cur.is_day : null, // 0/1 if provided
  };

  // hourly (robust)
  const hourly = extractHourly(root);

  // daily
  const dailySrc = Array.isArray(root.daily) ? root.daily : [];
  const daily = dailySrc.map((d, i) => {
    const t = d.temp || {};
    const min = t.min ?? d.min ?? null;
    const max = t.max ?? d.max ?? null;
    const pop = normPop(d.pop);
    const precip =
      d.precipitation ??
      getPrecipAmount(d.rain) ??
      getPrecipAmount(d.snow) ??
      0;
    const weather = d.weather ?? d.description ?? "";
    return {
      dt: d.dt ?? d.date ?? Math.floor(Date.now() / 1000) + (i + 1) * 86400,
      min,
      max,
      pop,
      precipitation: precip,
      weather,
      sunrise: d.sunrise ?? null,
      sunset: d.sunset ?? null,
    };
  });

  return {
    current: current.temp != null ? current : null,
    hourly,
    daily,
    summary: typeof p.summary === "string" ? p.summary : "",
    timezone: root.timezone ?? root.tz ?? null,
    _raw: p,
  };
}

const getDevice = () =>
  typeof window !== "undefined" && window.matchMedia?.("(max-width: 768px)")?.matches
    ? "mobile"
    : "desktop";

export default function WeatherApp() {
  const [place, setPlace] = useState(ATL);
  const [view, setView] = useState("now"); // "now" | "chatbot" | "community"
  const [weather, setWeather] = useState({ current: null, hourly: [], daily: [], summary: "", timezone: null });
  const [daily16, setDaily16] = useState([]);
  const [wLoading, setWLoading] = useState(false);
  const [wError, setWError] = useState("");
  const [debugRaw, setDebugRaw] = useState(null);

  // °C / °F toggle (persist)
  const [unit, setUnit] = useState(() => localStorage.getItem("unit") || "metric");
  useEffect(() => { localStorage.setItem("unit", unit); }, [unit]);

  function handleSearchSelect(p) {
    if (typeof p === "string") {
      setPlace({ name: p.trim() || ATL.name, lat: ATL.lat, lon: ATL.lon });
      return;
    }
    setPlace({
      name: p?.name || ATL.name,
      lat: isFiniteNum(p?.lat) ? p.lat : ATL.lat,
      lon: isFiniteNum(p?.lon) ? p.lon : ATL.lon,
    });
  }

  useEffect(() => {
    let abort = false;

    async function run() {
      try {
        setWLoading(true);
        setWError("");

        // current/hourly/daily + summary
        const r1 = await fetch(`${API_BASE}/api/weather/current`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ location: place.name, lat: place.lat, lon: place.lon }),
        });
        if (!r1.ok) {
          const t = await r1.text().catch(() => "");
          throw new Error(`HTTP ${r1.status} /api/weather/current ${t}`);
        }
        const p1 = await r1.json();
        if (abort) return;

        const norm = normalizePayload(p1);
        setWeather({
          current: norm.current,
          hourly: norm.hourly,
          daily: norm.daily,
          summary: norm.summary,
          timezone: norm.timezone,
        });
        setDebugRaw(norm._raw || p1);

        // 16‑day (optional)
        let ext = [];
        try {
          const r2 = await fetch(`${API_BASE}/api/weather/forecast16`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ location: place.name, days: 16 }),
          });
          if (r2.ok) {
            const p2 = await r2.json();
            const arr = Array.isArray(p2?.weather?.daily) ? p2.weather.daily : [];
            ext = arr;
          }
        } catch (_) {}
        setDaily16(ext.length ? ext : norm.daily.slice(0, 16));
      } catch (e) {
        if (!abort) {
          console.error(e);
          setWError(e.message || "Failed to load weather");
          setWeather({ current: null, hourly: [], daily: [], summary: "", timezone: null });
          setDaily16([]);
          setDebugRaw(null);
        }
      } finally {
        if (!abort) setWLoading(false);
      }
    }

    if (place?.name) run();
    return () => { abort = true; };
  }, [place.name, place.lat, place.lon]);

  const now = weather.current || {};
  const nowTemp = unit === "imperial" ? toF(now?.temp) : now?.temp;

  // ---------- isDay for selected city ----------
  const isDay = useMemo(() => {
    if (typeof now?.is_day === "number") return now.is_day === 1;

    if (now?.sunrise && now?.sunset) {
      const nowSec = Date.now() / 1000;
      return nowSec >= now.sunrise && nowSec < now.sunset;
    }

    try {
      if (weather?.timezone) {
        const hourStr = new Intl.DateTimeFormat("en-US", {
          hour: "2-digit",
          hour12: false,
          timeZone: weather.timezone,
        }).format(new Date());
        const hour = parseInt(hourStr, 10);
        return hour >= 7 && hour < 19;
      }
    } catch {}
    return fallbackIsDay();
  }, [now?.is_day, now?.sunrise, now?.sunset, weather?.timezone]);

  // ---------- SAFE condition string ----------
  const condition = useMemo(() => {
    const w = now?.weather;
    if (!w) return "clear";
    if (Array.isArray(w)) {
      const first = w[0];
      if (!first) return "clear";
      if (typeof first === "string") return normalizeCondition(first);
      return normalizeCondition(first.description ?? first.main ?? "clear");
    }
    if (typeof w === "object") {
      return normalizeCondition(w.description ?? w.main ?? "clear");
    }
    return normalizeCondition(w);
  }, [now?.weather]);

  const device = useMemo(
    () =>
      (typeof window !== "undefined" &&
        window.matchMedia?.("(max-width: 768px)")?.matches)
        ? "mobile" : "desktop",
    []
  );

  // ---------- SafeText for leftover odd values ----------
  const SafeText = ({ value }) => {
    if (value == null) return <>{""}</>;
    if (typeof value === "string" || typeof value === "number") return <>{value}</>;
    if (Array.isArray(value)) return <>{value.join(", ")}</>;
    return <>{String(value)}</>;
  };

  return (
    <div className="relative min-h-screen flex flex-col bg-transparent overflow-hidden">
      {/* Background MP4 overlay */}
      <WeatherOverlay condition={condition} isDay={isDay} device={device} />

      {/* Search */}
      <header className="px-4 pt-4">
        <div className="mx-auto w-full max-w-5xl">
          <SearchSection defaultValue={place?.name || ""} onSelect={handleSearchSelect} />
        </div>
      </header>

      {/* Status */}
      {wLoading && <div className="px-4 mt-2 text-xs text-gray-200">Loading weather…</div>}
      {!wLoading && wError && <div className="px-4 mt-2 text-xs text-red-300">{wError}</div>}

      {/* Header card */}
      <section className="px-4 mt-3">
        <div className="mx-auto w-full max-w-5xl">
          <div className="rounded-2xl bg-black/30 backdrop-blur-md text-white drop-shadow p-4">
            <div className="flex items-start justify-between gap-3">
              <div>
                <div className="text-sm/5 opacity-90">Now in</div>
                <div className="text-xl font-semibold"><SafeText value={place?.name} /></div>
                <div className="text-5xl font-bold mt-1">
                  {nowTemp != null ? Math.round(nowTemp) : "--"}°{unit === "imperial" ? "F" : "C"}
                </div>
                <div className="opacity-90 capitalize">
                  <SafeText value={condition || (weather.summary ? "" : "—")} />
                </div>
                {weather.summary && (
                  <div className="mt-3 opacity-95">
                    <SafeText value={weather.summary} />
                  </div>
                )}
              </div>

              {/* Unit toggle */}
              <div className="shrink-0">
                <button
                  onClick={() => setUnit((u) => (u === "metric" ? "imperial" : "metric"))}
                  className="px-3 py-1.5 rounded-lg bg-white/15 hover:bg-white/25 transition text-sm"
                  aria-label="Toggle temperature units"
                  title="Toggle °C/°F"
                >
                  °{unit === "imperial" ? "F" : "C"}
                </button>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Views */}
      <main className="px-4 mt-6 pb-28 text-white">
        <div className="mx-auto w-full max-w-5xl">
          {view === "now" && (
            <>
              {/* NEW: Hourly row (24 items max) */}
              <section className="mb-6">
                <Hourly
                  hourly={weather.hourly}
                  unit={unit}
                  timezone={weather.timezone || "local"}
                />
                {/* Tiny debug aid if hourly is empty */}
                {!weather.hourly?.length && (
                  <pre className="mt-3 text-xs bg-black/30 rounded-xl p-2 overflow-auto max-h-48">
                    Hourly is empty. First-level keys from backend (truncated):
                    {"\n"}
                    {JSON.stringify((debugRaw && (debugRaw.weather || debugRaw)) ? Object.keys(debugRaw.weather || debugRaw) : [], null, 2)}
                  </pre>
                )}
              </section>

              <section className="mb-6">
                <Radar
                  center={[
                    isFiniteNum(place?.lat) ? place.lat : ATL.lat,
                    isFiniteNum(place?.lon) ? place.lon : ATL.lon,
                  ]}
                  zoom={6}
                  height={320}
                  className="rounded-2xl overflow-hidden"
                />
              </section>

              <section>
                <Forecast hourly={weather.hourly} daily={weather.daily} daily16={daily16} unit={unit} />
              </section>
            </>
          )}

          {view === "chatbot" && <ChatBox location={place?.name || ATL.name} />}

          {view === "community" && (
            <div className="rounded-2xl bg-black/30 backdrop-blur-md text-white p-4">
              <Community city={place?.name || ""} />
            </div>
          )}

          {!wLoading && !wError && !weather.current && (
            <pre className="mt-4 p-3 text-xs bg-black/20 rounded overflow-auto max-h-64">
              No “current” parsed. Raw payload (truncated):
              {JSON.stringify(debugRaw, null, 2).slice(0, 1200)}…
            </pre>
          )}
        </div>
      </main>

      <BottomBar active={view} onNav={setView} />
    </div>
  );
}

/** ChatBox */
function ChatBox({ location }) {
  const [q, setQ] = useState("");
  const [a, setA] = useState("");
  const [loading, setLoading] = useState(false);

  async function ask(e) {
    e.preventDefault();
    if (!q.trim()) return;
    setLoading(true);
    setA("");

    try {
      const res = await fetch(`${API_BASE}/api/weather/chat`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ location, question: q }),
      });

      const contentType = res.headers.get("content-type") || "";
      const isJson = contentType.includes("application/json");
      const payload = isJson ? await res.json().catch(() => ({})) : { response: await res.text().catch(() => "") };

      if (!res.ok) {
        throw new Error(
          payload?.response?.toString().trim() ||
            "Sorry — the forecast assistant is unavailable right now. Please try again soon."
        );
      }
      setA(payload?.response || "No answer.");
    } catch (err) {
      setA(err.message || "Sorry — the forecast assistant is unavailable right now.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="rounded-2xl bg-black/30 backdrop-blur-md text-white p-4">
      <div className="font-semibold mb-2">Ask about the forecast</div>
      <form onSubmit={ask} className="flex gap-2">
        <input
          value={q}
          onChange={(e) => setQ(e.target.value)}
          placeholder={`Ask about ${location}…`}
          className="flex-1 px-3 py-2 rounded-lg bg-white/10 outline-none text-white placeholder-white/70"
        />
        <button className="px-3 py-2 rounded-lg bg-purple-600 text-white" disabled={loading}>
          {loading ? "Asking…" : "Ask"}
        </button>
      </form>
      {a && <div className="mt-3 text-sm whitespace-pre-wrap">{a}</div>}
    </div>
  );
}
